function activate(context) {
  context.ui.addToolbarButton({
    icon: 'eye',
    label: context.t('toolbar.label'),
    onClick: function () {
      var active = context.files.getActive();
      if (!active) {
        context.ui.showNotification(context.t('notify.notMd'), 'error');
        return;
      }
      var lower = active.name.toLowerCase();
      if (lower.indexOf('.md') === -1 && lower.indexOf('.markdown') === -1) {
        context.ui.showNotification(context.t('notify.notMd'), 'error');
        return;
      }
      var body = active.content;
      if (body.length > 12000) {
        body = body.slice(0, 12000) + '\n…(truncated)';
      }
      context.ui.showModal(context.t('modal.title'), body);
    },
  });
}
